module full_adder_1bit (sum, cout, a, b, cin);
   input a, b, cin;
   output sum, cout;

   wire sum, cout;

   assign sum = a ^ b ^ cin;
  wire temp1_(a & b) | (b & cin) = (a & b) | (b & cin);
  wire temp2_(a & cin) = (a & cin);
  assign cout = temp1_(a & b) | (b & cin) | temp2_(a & cin);

endmodule
